	('3b3fc390-5906-41a5-86cd-c1715f65a7eb', 'To Space and Back', 'Best for ages 10 - adult Space exploration helps us discover a universe of unimaginable scale and beauty, reaching down to our world to influence the way we live. Discover an extraordinary story of human ingenuity and incredible engineering, describing how the technology that transports us through space paves the way for devices and apps we use every day. Discover how we’ve been changed by space exploration, and what we owe to curiosity and the spirit of discovery. Produced by Sky-Skan, Inc. The', '2026-05-23 14:45:00+00', '2026-05-23 15:10:00+00', 'America/Chicago', 'Lafayette Science Museum', '433 Jefferson St, Lafayette, LA 70501, USA', '4d4f7e7d-bb99-46ba-b9c3-de67dd083d3f', 30.2241000, -92.0198000, NULL, NULL, 0.00, true, 'https://lafayettesciencemuseum.org/events/to-space-and-back/?occurrence=2026-05-23', 'Lafayette Science Museum', '71d476b0-79d2-4236-b6f3-d7176aaaa77d', '["https://lafayettesciencemuseum.org/wp-content/uploads/448668708_867937655365959_766820210818810894_n.jpg"]', 'draft', 0.550, 'ollama', NULL, false, false, 0, '''10'':8 ''433'':93 ''70501'':98 ''adult'':9 ''age'':7 ''app'':58 ''back'':4 ''beauti'':21 ''best'':5 ''chang'':68 ''curios'':77 ''day'':62 ''describ'':43 ''devic'':56 ''discov'':14,33,63 ''discoveri'':82 ''engin'':42 ''everi'':61 ''explor'':11,71 ''extraordinari'':35 ''help'':12 ''human'':38 ''inc'':88 ''incred'':41 ''influenc'':28 ''ingenu'':39 ''jefferson'':94 ''la'':97 ''lafayett'':90,96 ''live'':32 ''museum'':92 ''owe'':75 ''pave'':52 ''produc'':83 ''reach'':22 ''scale'':19 ''scienc'':91 ''skan'':87 ''sky'':86 ''sky-skan'':85 ''space'':2,10,51,70 ''spirit'':80 ''st'':95 ''stori'':36 ''technolog'':46 ''transport'':48 ''unimagin'':18 ''univers'':16 ''us'':13,49 ''usa'':99 ''use'':60 ''ve'':66 ''way'':30,54 ''world'':26', '2026-05-21 02:08:32.976787+00', '2026-05-21 19:20:33.170342+00', '{}', NULL, NULL, 'qwen3:1.7b', 'fallback'),
	('a25f6525-5c5d-4166-bdc5-96526206dc87', 'Two Small Pieces of Glass', 'Best for grade 5 - adult Join two kids going to a star party where they meet the astronomy lady, who tells them all about telescopes and what astronomers find with them. Discover the amazing world of telescopes and the universe! This show is about 25 minutes long.', '2026-05-31 13:30:00+00', '2026-05-31 13:55:00+00', 'America/Chicago', 'Lafayette Science Museum', '433 Jefferson St, Lafayette, LA 70501, USA', '4d4f7e7d-bb99-46ba-b9c3-de67dd083d3f', 30.2241000, -92.0198000, NULL, NULL, 0.00, true, 'https://lafayettesciencemuseum.org/events/two-small-pieces-of-glass/?occurrence=2026-05-31', 'Lafayette Science Museum', '71d476b0-79d2-4236-b6f3-d7176aaaa77d', '["https://lafayettesciencemuseum.org/wp-content/uploads/435254236_818089537017438_3102293335838648120_n.jpg"]', 'draft', 0.000, 'ollama', NULL, false, false, 0, '''25'':50 ''433'':56 ''5'':9 ''70501'':61 ''adult'':10 ''amaz'':39 ''astronom'':33 ''astronomi'':23 ''best'':6 ''discov'':37 ''find'':34 ''glass'':5 ''go'':14 ''grade'':8 ''jefferson'':57 ''join'':11 ''kid'':13 ''la'':60 ''ladi'':24 ''lafayett'':53,59 ''long'':52 ''meet'':21 ''minut'':51 ''museum'':55 ''parti'':18 ''piec'':3 ''scienc'':54 ''show'':47 ''small'':2 ''st'':58 ''star'':17 ''telescop'':30,42 ''tell'':26 ''two'':1,12 ''univers'':45 ''usa'':62 ''world'':40', '2026-05-21 02:08:42.99105+00', '2026-05-21 19:31:32.364521+00', '{}', NULL, NULL, 'qwen3:1.7b', 'fallback'),
	('aeb0dda0-f2a8-4f2c-9a48-d00a5dbdd062', 'Rock the Block: Louisiana Music Museum’s Kick-Off Party!', 'Join us for a vibrant downtown street party dedicated to the past, present, and future of our state’s incredible sound.We’re taking over the 100 block of Vermilion St. for an evening of live local legends, downtown flavors, and a chance to leave your mark on the museum before the first stone is even laid. Whether you''re a lifelong zydeco fan, a jazz aficionado, or just looking for the best Saturday night vibe in Lafayette, there’s a spot on the block for you.WHAT''S ON THE SETLIST: The Main Stage', '2026-05-16 22:00:00+00', '2026-05-17 01:00:00+00', 'America/Chicago', 'Louisiana Music Museum', '121 W. Vermilion St.', '4d4f7e7d-bb99-46ba-b9c3-de67dd083d3f', 30.2239938, -92.0190700, NULL, NULL, 0.00, true, 'https://acadianacenterforthearts.org/events/rock-the-block/?occurrence=2026-05-16', 'Acadiana Center for the Arts', 'bab78b4c-e675-46cc-a2df-0a4406d1ed66', '["https://acadianacenterforthearts.org/wp-content/uploads/2026/04/Rock-the-block-featured-image-scaled.png"]', 'draft', 0.540, 'ollama', NULL, false, false, 0, '''100'':37 ''121'':108 ''aficionado'':77 ''best'':83 ''block'':3,38,95 ''chanc'':53 ''dedic'':20 ''downtown'':17,49 ''even'':44,66 ''fan'':74 ''first'':63 ''flavor'':50 ''futur'':26 ''incred'':31 ''jazz'':76 ''join'':12 ''kick'':9 ''kick-off'':8 ''lafayett'':88 ''laid'':67 ''leav'':55 ''legend'':48 ''lifelong'':72 ''live'':46 ''local'':47 ''look'':80 ''louisiana'':4,105 ''main'':103 ''mark'':57 ''museum'':6,60,107 ''music'':5,106 ''night'':85 ''parti'':11,19 ''past'':23 ''present'':24 ''re'':33,70 ''rock'':1 ''saturday'':84 ''setlist'':101 ''sound.we'':32 ''spot'':92 ''st'':41,111 ''stage'':104 ''state'':29 ''stone'':64 ''street'':18 ''take'':34 ''us'':13 ''vermilion'':40,110 ''vibe'':86 ''vibrant'':16 ''w'':109 ''whether'':68 ''you.what'':97 ''zydeco'':73', '2026-05-21 02:08:35.806637+00', '2026-05-21 19:00:31.737817+00', '{}', NULL, NULL, 'qwen3:1.7