	('d170fbf9-e4da-4ff0-9844-e48a2556d6d7', 'To Space and Back', 'Best for ages 10 - adult Space exploration helps us discover a universe of unimaginable scale and beauty, reaching down to our world to influence the way we live. Discover an extraordinary story of human ingenuity and incredible engineering, describing how the technology that transports us through space paves the way for devices and apps we use every day. Discover how we’ve been changed by space exploration, and what we owe to curiosity and the spirit of discovery. Produced by Sky-Skan, Inc. The', '2026-05-24 14:45:00+00', '2026-05-24 15:10:00+00', 'America/Chicago', 'Lafayette Science Museum', '433 Jefferson St, Lafayette, LA 70501, USA', '4d4f7e7d-bb99-46ba-b9c3-de67dd083d3f', 30.2241000, -92.0198000, NULL, NULL, 0.00, true, 'https://lafayettesciencemuseum.org/events/to-space-and-back/?occurrence=2026-05-24', 'Lafayette Science Museum', '71d476b0-79d2-4236-b6f3-d7176aaaa77d', '["https://lafayettesciencemuseum.org/wp-content/uploads/448668708_867937655365959_766820210818810894_n.jpg"]', 'draft', 0.550, 'ollama', NULL, false, false, 0, '''10'':8 ''433'':93 ''70501'':98 ''adult'':9 ''age'':7 ''app'':58 ''back'':4 ''beauti'':21 ''best'':5 ''chang'':68 ''curios'':77 ''day'':62 ''describ'':43 ''devic'':56 ''discov'':14,33,63 ''discoveri'':82 ''engin'':42 ''everi'':61 ''explor'':11,71 ''extraordinari'':35 ''help'':12 ''human'':38 ''inc'':88 ''incred'':41 ''influenc'':28 ''ingenu'':39 ''jefferson'':94 ''la'':97 ''lafayett'':90,96 ''live'':32 ''museum'':92 ''owe'':75 ''pave'':52 ''produc'':83 ''reach'':22 ''scale'':19 ''scienc'':91 ''skan'':87 ''sky'':86 ''sky-skan'':85 ''space'':2,10,51,70 ''spirit'':80 ''st'':95 ''stori'':36 ''technolog'':46 ''transport'':48 ''unimagin'':18 ''univers'':16 ''us'':13,49 ''usa'':99 ''use'':60 ''ve'':66 ''way'':30,54 ''world'':26', '2026-05-21 02:08:35.993417+00', '2026-05-21 19:25:18.612984+00', '{}', NULL, NULL, 'qwen3:1.7b', 'fallback'),
