	('5fa43d8d-8bfe-487e-941e-122fd1152ee3', 'Alejandro Escovedo & the Electric Saints', 'With support from Calder Allen Rock | Alternative No one has really ever been able to define themselves and their music like singer-songwriter Alejandro Escovedo does. His life in music of all kinds sometimes feels like a swirl through the sky, where his songs point out all the majesty and mystery of how he sees the world. The sounds he makes take him places that he might not even predict, but once there, greatness always follows. It''s just the way Escovedo is. It has happened over and over for ', '2026-05-02 00:30:00+00', '2026-05-02 02:30:00+00', 'America/Chicago', 'Acadiana Center for the Arts - James Devin Moncus Theater', '101 W. Vermilion Street', '4d4f7e7d-bb99-46ba-b9c3-de67dd083d3f', 30.2238767, -92.0192319, NULL, NULL, 45.00, false, 'https://acadianacenterforthearts.org/events/alejandro-escovedo/?occurrence=2026-05-01', 'Acadiana Center for the Arts', 'bab78b4c-e675-46cc-a2df-0a4406d1ed66', '["https://acadianacenterforthearts.org/wp-content/uploads/2025/12/trioAE2025-scaled.jpeg"]', 'draft', 0.630, 'ollama', NULL, false, false, 0, '''101'':106 ''abl'':19 ''acadiana'':97 ''alejandro'':1,30 ''allen'':10 ''altern'':12 ''alway'':81 ''art'':101 ''calder'':9 ''center'':98 ''defin'':21 ''devin'':103 ''electr'':4 ''escovedo'':2,31,88 ''even'':75 ''ever'':17 ''feel'':41 ''follow'':82 ''great'':80 ''happen'':92 ''jame'':102 ''kind'':39 ''life'':34 ''like'':26,42 ''majesti'':55 ''make'':67 ''might'':73 ''moncus'':104 ''music'':25,36 ''mysteri'':57 ''one'':14 ''place'':70 ''point'':51 ''predict'':76 ''realli'':16 ''rock'':11 ''saint'':5 ''see'':61 ''singer'':28 ''singer-songwrit'':27 ''sky'':47 ''sometim'':40 ''song'':50 ''songwrit'':29 ''sound'':65 ''street'':109 ''support'':7 ''swirl'':44 ''take'':68 ''theater'':105 ''vermilion'':108 ''w'':107 ''way'':87 ''world'':63', '2026-05-21 02:08:31.769629+00', '2026-05-21 18:55:25.437936+00', '{}', NULL, NULL, 'qwen3:1.7b', 'fallback'),
