	('476b5118-840e-425d-8ff2-61773138c1a9', 'Nature Walks', 'Join us for Nature Walks this spring with the Acadiana Native Plant Project at Moncus Park. These guided walks invite you to slow down and explore the park’s diverse habitats while learning about the plants that shape our local landscape. Led by knowledgeable experts, each walk offers insight into native and invasive species and their roles in supporting wildlife, pollination, and healthy stormwater systems. Nature Walks are a chance to deepen your connection to the natural world and better unde', '2026-05-12 22:30:00+00', '2026-05-12 23:30:00+00', 'America/Chicago', 'Moncus Park', NULL, '4d4f7e7d-bb99-46ba-b9c3-de67dd083d3f', 30.2241000, -92.0198000, NULL, NULL, 0.00, true, 'https://moncuspark.org/calendar-events/nature-walks/', 'Moncus Park', 'ef4657c9-22c0-401a-ba3c-cf3dd5be10f5', '["https://moncuspark.org/wp-content/uploads/2026/01/Screenshot-2026-02-26-115914.png"]', 'draft', 0.580, 'ollama', NULL, false, true, 0, '''acadiana'':12 ''better'':82 ''chanc'':72 ''connect'':76 ''deepen'':74 ''divers'':32 ''expert'':47 ''explor'':28 ''guid'':20 ''habitat'':33 ''healthi'':65 ''insight'':51 ''invas'':55 ''invit'':22 ''join'':3 ''knowledg'':46 ''landscap'':43 ''learn'':35 ''led'':44 ''local'':42 ''moncus'':17,84 ''nativ'':13,53 ''natur'':1,6,68,79 ''offer'':50 ''park'':18,30,85 ''plant'':14,38 ''pollin'':63 ''project'':15 ''role'':59 ''shape'':40 ''slow'':25 ''speci'':56 ''spring'':9 ''stormwat'':66 ''support'':61 ''system'':67 ''und'':83 ''us'':4 ''walk'':2,7,21,49,69 ''wildlif'':62 ''world'':80', '2026-05-21 02:08:34.720473+00', '2026-05-21 20:45:18.35825+00', '{}', NULL, NULL, 'qwen3:1.7b', 'fallback'),
