	('5c642cb7-de36-4ee6-a316-30c34835e5df', '476b5118-840e-425d-8ff2-61773138c1a9', 'cb5fa48b-4be4-4184-b5e5-63eb72689aed', 'import', 'ollama', 'qwen3:1.7b', 'fallback', 'Nature Walks', 'Join us for Nature Walks this spring with the Acadiana Native Plant Project at Moncus Park. These guided walks invite you to slow down and explore the park’s diverse habitats while learning about the plants that shape our local landscape. Led by knowledgeable experts, each walk offers insight into native and invasive species and their roles in supporting wildlife, pollination, and healthy stormwater systems. Nature Walks are a chance to deepen your connection to the natural world and better unde', '["free", "outdoor", "indoor", "toddler-friendly", "baby-friendly", "teen-friendly", "weekend", "educational", "arts-crafts", "music", "sensory-friendly", "family-festival", "storytime", "stem", "sports", "cooking", "nature", "community", "holiday", "playgroup"]', '[{"slug": "outdoor", "reason": "Matched keyword rule hits: park, nature.", "confidence": 0.58, "matched_keywords": ["park", "nature"]}]', '{"price": null, "age_max": null, "age_min": null, "is_free": false, "venue_name": "Moncus Park"}', 'Keyword fallback classified this event because the configured AI provider was unavailable. Matching keywords were used to assign tags.', 'Signal timed out.', 30096, '2026-05-21 02:09:14.344301+00'),
	('0a170d9d-5897-4f48-bcb5-af1630206e93', 'd1147498-0009-43a9-a597-93cce5bcdbac', 'b4feafb3-0989-4699-a480-f36664d6ed21', 'import', 'ollama', 'qwen3:1.7b', 'fallback', 'Atchafalaya Reunion', 'A legendary Cajun rock band reunites. Atchafalaya is known for blending traditional Cajun sounds with southern rock, country and blues influence. Formed in the late 1970s, the band has been performing together for over 45 years, earning a loyal fan base across Louisiana and beyond. Atchafalaya gained National and International attention through their high energy performances, heartfelt songwriting, and commitment to preserving Cajun culture while evolving their sound. They toured overseas, perfo', '["free", "outdoor", "indoor", "toddler-friendly", "baby-friendly", "teen-friendly", "weekend", "educational", "arts-crafts", "music", "sensory-friendly", "family-festival", "storytime", "stem", "sports", "cooking", "nature", "community", "holiday", "playgroup"]', '[{"slug": "music", "reason": "Matched keyword rule hits: song, band.", "confidence": 0.58, "matched_keywords": ["song", "band"]}]', '{"price": null, "age_max": null, "age_min": null, "is_free": false, "venue_name": null}', 'Keyword fallback classified this event because the configured AI provider was unavailable. Matching keywords were used to assign tags.', 'Signal timed out.', 30143, '2026-05-21 02:11:07.589981+00'),
