	('4979925b-8a36-4447-bb36-29fdc94c632f', '96f9199b-c7f4-4cdb-8c63-39bac2672dd3', 'cb5fa48b-4be4-4184-b5e5-63eb72689aed', 'import', 'ollama', 'qwen3:1.7b', 'fallback', 'Yoga in the Park', 'Transform your Wednesday evenings with Yoga in the Park at Moncus Park, part of the "Fit For All" series presented by Louisiana Orthopaedic Specialists & Orthopedic Urgent Care. Every Wednesday at 6:00 p.m., join our supportive community in celebrating wellness amidst nature''s beauty. Whether you''re a seasoned yogi or a curious beginner, these sessions offer the perfect midweek reset. Location: First Horizon Amphitheater What you need to know: Every Wednesday at 6:00 p.m. Bring your own mat Wear', '["free", "outdoor", "indoor", "toddler-friendly", "baby-friendly", "teen-friendly", "weekend", "educational", "arts-crafts", "music", "sensory-friendly", "family-festival", "storytime", "stem", "sports", "cooking", "nature", "community", "holiday", "playgroup"]', '[{"slug": "outdoor", "reason": "Matched keyword rule hits: park, nature.", "confidence": 0.58, "matched_keywords": ["park", "nature"]}, {"slug": "sports", "reason": "Matched keyword rule hits: yoga.", "confidence": 0.55, "matched_keywords": ["yoga"]}]', '{"price": null, "age_max": null, "age_min": null, "is_free": false, "venue_name": "Moncus Park"}', 'Keyword fallback classified this event because the configured AI provider was unavailable. Matching keywords were used to assign tags.', 'Signal timed out.', 30129, '2026-05-21 02:11:29.38649+00'),
