	('161e5d5f-5835-4e2e-bf33-9243859533d2', 'd115d0db-1aaf-49fc-a3d2-be1091694732', 'cb5fa48b-4be4-4184-b5e5-63eb72689aed', 'import', 'ollama', 'qwen3:1.7b', 'success', 'Lafayette Farmers & Artisans Market', 'EVERY SATURDAY | 8:00 AM TO 12:00 PM The Lafayette Farmers and Artisans Market at Moncus Park is a vibrant weekly event that brings together local farmers, artisans, and craftspeople to showcase their fresh produce, handmade goods, and unique crafts. Held every Saturday morning, the market offers a wonderful opportunity for the community to shop locally, enjoy a Cajun Jam, and connect with local vendors. It''s a lively hub for those seeking fresh, locally sourced products and a great way to suppo', '["free", "outdoor", "indoor", "toddler-friendly", "baby-friendly", "teen-friendly", "weekend", "educational", "arts-crafts", "music", "sensory-friendly", "family-festival", "storytime", "stem", "sports", "cooking", "nature", "community", "holiday", "playgroup"]', '[{"slug": "weekend", "reason": "Event is held every Saturday, which aligns with the ''Weekend'' tag.", "confidence": 0.9, "matched_keywords": []}, {"slug": "arts-crafts", "reason": "Event features local artisans and craftspeople, aligning with the ''Arts & Crafts'' tag.", "confidence": 0.8, "matched_keywords": []}, {"slug": "community", "reason": "Event is a community-driven gathering where locals can shop, enjoy, and connect.", "confidence": 0.7, "matched_keywords": []}, {"slug": "outdoor", "reason": "Event is held at Moncus Park, which is an outdoor space.", "confidence": 0.6, "matched_keywords": []}]', '{"price": null, "age_max": null, "age_min": null, "is_free": true, "venue_name": "Moncus Park"}', 'The Lafayette Farmers & Artisans Market is a weekend event held at Moncus Park, featuring local farmers, artisans, and craftspeople. It is free and offers a community-driven experience where attendees can shop locally, enjoy a Cajun Jam, and connect with vendors. The event is held every Saturday morning and i