	('437a8580-2008-4f00-bd9b-397c3647d370', '476b5118-840e-425d-8ff2-61773138c1a9', 'cb5fa48b-4be4-4184-b5e5-63eb72689aed', 'import', 'ollama', 'qwen3:1.7b', 'success', 'Nature Walks', 'Join us for Nature Walks this spring with the Acadiana Native Plant Project at Moncus Park. These guided walks invite you to slow down and explore the park’s diverse habitats while learning about the plants that shape our local landscape. Led by knowledgeable experts, each walk offers insight into native and invasive species and their roles in supporting wildlife, pollination, and healthy stormwater systems. Nature Walks are a chance to deepen your connection to the natural world and better unde', '["free", "outdoor", "indoor", "toddler-friendly", "baby-friendly", "teen-friendly", "weekend", "educational", "arts-crafts", "music", "sensory-friendly", "family-festival", "storytime", "stem", "sports", "cooking", "nature", "community", "holiday", "playgroup"]', '[{"slug": "nature", "reason": "Event explicitly mentions ''Nature Walks'' and ''exploring the park’s diverse habitats''", "confidence": 0.9, "matched_keywords": []}, {"slug": "educational", "reason": "Event describes guided walks with expert-led insights into native and invasive species", "confidence": 0.8, "matched_keywords": []}, {"slug": "weekend", "reason": "Event occurs in spring, implying it is likely on a weekend", "confidence": 0.7, "matched_keywords": []}, {"slug": "free", "reason": "Event description does not mention a price, but implies it is a community event", "confidence": 0.6, "matched_keywords": []}]', '{"price": null, "age_max": null, "age_min": null, "is_free": true, "venue_name": "Moncus Park"}', 'This event is a guided nature walk for families, focusing on exploring diverse habitats and learning about native plants. It is free and takes place at Moncus Park, a community-based outdoor activity.', NULL, 10156, '2026-05-21 02:20:24.369083+00'),
